module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const color = args.color || 'var(--accent-color)';
const sep = args.sep || '→';
const terms = sections.map((s) => (s || '').trim()).filter(Boolean);
if (!terms.length) return `<div>(sequence: one term per section)</div>`;
let html = `\n\n<div class="mdp-mod-sequence" style="--sq-c:${color};"><div class="mdp-sq-strip">`;
terms.forEach((t, i) => {
  if (i) html += `<span class="mdp-sq-sep">${esc(sep)}</span>`;
  html += `<span class="mdp-sq-term">\n\n${t}\n\n</span>`;
});
if (String(args.tail) === 'true') html += `<span class="mdp-sq-sep">${esc(sep)}</span><span class="mdp-sq-term mdp-sq-tail">…</span>`;
html += `</div>`;
if (args.rule) html += `<div class="mdp-sq-rule">\n\n${args.rule}\n\n</div>`;
html += `</div>\n\n`;
return html;
